import { createApp } from 'vue'
import App from './App.vue'
import router from './router'

import PrimeVue from 'primevue/config';
import Aura from '@primeuix/primeuix/themes/dist/aura';


createApp(App).use(router).mount('#app');

app.use(PrimeVue, {
    theme: {
        preset: Aura
    }
 });
